func New(cfg *config.Config, timeout time.Duration, rateLimit float64) *Client {
	homeDir, _ := os.UserHomeDir()
	cacheDir := filepath.Join(homeDir, ".cache", "yahoo-finance-pp-cli")
	jar, _ := cookiejar.New(nil)
	c := &Client{
		BaseURL:    strings.TrimRight(cfg.BaseURL, "/"),
		Config:     cfg,
		HTTPClient: &http.Client{Timeout: timeout, Jar: jar},
		cacheDir:   cacheDir,
		limiter:    newAdaptiveLimiter(rateLimit),
	}
	c.loadCookiesFromDisk()
	return c
}

// yahooCookieFile returns the path where session cookies are cached.
func (c *Client) yahooCookieFile() string {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		return ""
	}
	return filepath.Join(homeDir, ".config", "yahoo-finance-pp-cli", "session.json")
}

type cookieRecord struct {
	URL     string    `json:"url"`
	Name    string    `json:"name"`
	Value   string    `json:"value"`
	Path    string    `json:"path"`
	Expires time.Time `json:"expires"`
}

type sessionFile struct {
	Crumb   string         `json:"crumb"`
	Cookies []cookieRecord `json:"cookies"`
	Updated time.Time      `json:"updated"`
}

func (c *Client) loadCookiesFromDisk() {
	path := c.yahooCookieFile()
	if path == "" {
		return
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return
	}
	var sess sessionFile
	if err := json.Unmarshal(data, &sess); err != nil {
		return
	}
	if time.Since(sess.Updated) > 24*time.Hour {
		return // stale
	}
	c.crumb = sess.Crumb
	if c.HTTPClient.Jar == nil {
		return
	}
	for _, rec := range sess.Cookies {
		u, err := url.Parse(rec.URL)
		if err != nil {
			continue
		}
		c.HTTPClient.Jar.SetCookies(u, []*http.Cookie{{
			Name:    rec.Name,
			Value:   rec.Value,
			Path:    rec.Path,
			Expires: rec.Expires,
		}})
	}
}

func (c *Client) saveCookiesToDisk() {
	path := c.yahooCookieFile()
	if path == "" || c.HTTPClient.Jar == nil {
		return
	}
	var recs []cookieRecord
	for _, rawURL := range []string{"https://yahoo.com/", "https://finance.yahoo.com/", "https://query1.finance.yahoo.com/", "https://query2.finance.yahoo.com/"} {
		u, err := url.Parse(rawURL)
		if err != nil {
			continue
		}
		for _, ck := range c.HTTPClient.Jar.Cookies(u) {
			recs = append(recs, cookieRecord{
				URL:     rawURL,
				Name:    ck.Name,
				Value:   ck.Value,
				Path:    ck.Path,
				Expires: ck.Expires,
			})
		}
	}
	sess := sessionFile{Crumb: c.crumb, Cookies: recs, Updated: time.Now()}
	data, err := json.MarshalIndent(sess, "", "  ")
	if err != nil {
		return
	}
	_ = os.MkdirAll(filepath.Dir(path), 0o755)
	_ = os.WriteFile(path, data, 0o600)
}

// SetChromeCookies imports cookies captured from a live Chrome profile. Used by
// `auth login-chrome` when the crumb handshake is blocked from the user's IP.
func (c *Client) SetChromeCookies(cookies []*http.Cookie, crumb string) error {
	if c.HTTPClient.Jar == nil {
		return fmt.Errorf("client has no cookie jar")
	}
	for _, domain := range []string{"https://yahoo.com/", "https://finance.yahoo.com/"} {
		u, err := url.Parse(domain)
		if err != nil {
			continue
		}
		c.HTTPClient.Jar.SetCookies(u, cookies)
	}
	c.crumbMu.Lock()
	c.crumb = crumb
	c.crumbMu.Unlock()
	c.saveCookiesToDisk()
	return nil
}

// ensureCrumb establishes the Yahoo session (cookies + crumb) if not already
// valid. Safe to call concurrently.
func (c *Client) ensureCrumb() (string, error) {
	c.crumbMu.Lock()
	if c.crumb != "" {
		crumb := c.crumb
		c.crumbMu.Unlock()
		return crumb, nil
	}
	c.crumbMu.Unlock()

	// Step 1: session bootstrap to get A1/B1 cookies
	req, err := http.NewRequest("GET", yahooBootstrapURL, nil)
	if err != nil {
		return "", fmt.Errorf("crumb bootstrap: %w", err)
	}
	req.Header.Set("User-Agent", yahooUserAgent)
	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		return "", fmt.Errorf("crumb bootstrap: %w", err)
	}
	_, _ = io.Copy(io.Discard, resp.Body)
	resp.Body.Close()

	// Step 2: fetch crumb
	req2, err := http.NewRequest("GET", yahooCrumbURL, nil)
	if err != nil {
		return "", fmt.Errorf("crumb fetch: %w", err)
	}
	req2.Header.Set("User-Agent", yahooUserAgent)
	resp2, err := c.HTTPClient.Do(req2)
	if err != nil {
		return "", fmt.Errorf("crumb fetch: %w", err)
	}
	body, _ := io.ReadAll(resp2.Body)
	resp2.Body.Close()

	if resp2.StatusCode >= 400 {
		return "", fmt.Errorf("crumb fetch returned HTTP %d: %s — try `yahoo-finance-pp-cli auth login-chrome` to import browser cookies", resp2.StatusCode, truncateBody(body))
	}
	crumb := strings.TrimSpace(string(body))
	if crumb == "" || strings.Contains(crumb, "Too Many Requests") {
		return "", fmt.Errorf("crumb endpoint rate-limited or empty (got %q) — try `yahoo-finance-pp-cli auth login-chrome`", crumb)
	}

	c.crumbMu.Lock()
	c.crumb = crumb
	c.crumbMu.Unlock()
	c.saveCookiesToDisk()
	return crumb, nil
}

// InvalidateCrumb clears the cached crumb so the next call re-bootstraps.
func (c *Client) InvalidateCrumb() {
	c.crumbMu.Lock()
	c.crumb = ""
	c.crumbMu.Unlock()
}

// Crumb returns the current crumb without triggering a bootstrap. Empty if not set.
func (c *Client) Crumb() string {
	c.crumbMu.Lock()
	defer c.crumbMu.Unlock()
	return c.crumb
}

